## 📋 AI日报生成脚本（示例）

这是一个基础的日报生成脚本框架，你可以根据实际需求修改。

```javascript
const { exec } = require('child_process');
const fs = require('fs');
const path = require('path');

/**
 * 生成AI日报
 * 读取生成的日报并发送到飞书
 */
async function generateDailyReport() {
    const now = new Date();
    const dateStr = now.toISOString().split('T')[0].replace(/-/g, ':'); // YYYY:MM:DD

    const reportPath = path.join(__dirname, '../../memory', `${dateStr}.md`);

    console.log('📰 开始生成日报...');
    console.log(`日期: ${dateStr}`);

    try {
        // 检查日报文件是否存在
        if (fs.existsSync(reportPath)) {
            console.log('📁 日报文件已存在，追加内容');

            // 这里应该是调用你现有的日报生成逻辑
            // 例如：const report = await generateAIReport();
            // fs.appendFileSync(reportPath, report);

            console.log('✅ 日报更新成功');
        } else {
            console.log('📝 日报文件不存在，需要生成');
            // 生成新日报
            // const report = await generateAIReport();
            // fs.writeFileSync(reportPath, report);

            console.log('✅ 新日报已生成');
        }
    } catch (err) {
        console.error('❌ 生成失败:', err);
        process.exit(1);
    }
}

// 执行生成
generateDailyReport();
```

### 📝 使用说明

1. 将此脚本保存到 `/workspace/projects/workspace/agents/main/scripts/daily-report.js`
2. 修改 `generateDailyReport()` 函数中的调用，适配你现有的日报生成逻辑
3. 确保 `memory/` 目录路径正确

### 🔗 关键变量说明

- `dateStr`: 日报日期（格式 YYYY:MM:DD）
- `reportPath`: 日报文件路径

---

**💡 提示**：
- 你的日报生成逻辑应该在独立的模块中（如 `ai-report-generator.js`）
- 本脚本主要负责文件路径处理和调用

